/* ============================================================
   *** TEMPORARY -- QA DEV-TEST (TRANSACTION ROLLS BACK) -- DO NOT COMMIT ***
   US 5462916 -- 232_Metals_CSMS68855869
   Real deploy ops + real verification inside ONE transaction, then ROLLBACK.
   PASS 1 applies; PASS 2 re-runs the same ops (idempotency, expect all 0);
   then AC verification against the uncommitted state. Nothing persists. QA only.
============================================================ */
SET NOCOUNT ON;
SET XACT_ABORT ON;
DECLARE @Msg NVARCHAR(4000) = '"';
DECLARE @CRLF VARCHAR(2) = CHAR(13)+CHAR(10);
DECLARE @EffectiveDate DATETIME = N'2026-06-08 00:00:00';
DECLARE @RetireDate DATETIME = N'2026-06-07 23:59:59';
DECLARE @Op1 INT = 0;
DECLARE @Op2 INT = 0;
DECLARE @Op3 INT = 0;
DECLARE @Op4 INT = 0;
DECLARE @Op1b INT = 0;
DECLARE @Op2b INT = 0;
DECLARE @Op3b INT = 0;
DECLARE @Op4b INT = 0;

IF OBJECT_ID('dbo.tmdHTSAdditional','U') IS NULL
BEGIN
    SET @Msg = @Msg + @CRLF + ' - ERROR: dbo.tmdHTSAdditional does not exist' + CHAR(10) + '"';
    SELECT [Phase]='ERROR', [Msg]=@Msg;
    RETURN;
END
IF SCHEMA_ID('bck') IS NULL
BEGIN
    SET @Msg = @Msg + @CRLF + ' - ERROR: backup schema does not exist' + CHAR(10) + '"';
    SELECT [Phase]='ERROR', [Msg]=@Msg;
    RETURN;
END
BEGIN TRY
    BEGIN TRANSACTION;

    /* ===== PASS 1 (apply the real ops) ===== */
    /* ---- Backup (idempotent; never overwritten) ---- */
    IF OBJECT_ID(N'[bck].[bck_tmdHTSAdditional_232_Metals_CSMS68855869_20260610_5462916]','U') IS NULL
    BEGIN
        DECLARE @BackupSQL nvarchar(max) = N'SELECT [HTSNum], [Chapter99], [CountryofOrigin], [StartEffDate], [EndEffDate], [TariffType], [TariffGroup], [RequiredStatusCode], [ValidationLevel], [ExportDate] INTO [bck].[bck_tmdHTSAdditional_232_Metals_CSMS68855869_20260610_5462916] FROM dbo.tmdHTSAdditional WITH (NOLOCK)';
        EXEC sys.sp_executesql @BackupSQL;
        SET @Msg = @Msg + @CRLF + ' - Backup created.';
    END
    ELSE SET @Msg = @Msg + @CRLF + ' - Backup already exists. Skipping.';

    /* -- 1. DELETE Deletes -- */
    DELETE FROM dbo.tmdHTSAdditional
    WHERE Chapter99 = '99038212' AND TariffType = '232' AND ( (ISNULL(HTSNum,'') = '' AND ISNULL(CountryofOrigin,'') IN ('BY','CU','KP','RU')) OR (ISNULL(HTSNum,'') <> '' AND ISNULL(CountryofOrigin,'') = '') );
    SET @Op1 = @@ROWCOUNT;

    /* -- 2. UPDATE Update_StartEffDate -- */
    DECLARE @Stg2 TABLE (
        [HTSNum] varchar(20),
        [Chapter99] varchar(20),
        [TariffType] varchar(20),
        [New_StartEffDate] datetime
    );

    UPDATE t
       SET t.[StartEffDate] = k.[New_StartEffDate]
    FROM dbo.tmdHTSAdditional t
    JOIN @Stg2 k
      ON  ISNULL(t.[HTSNum],'') = ISNULL(k.[HTSNum],'')
      AND t.[Chapter99] = k.[Chapter99]
      AND t.[TariffType] = k.[TariffType]
    WHERE t.StartEffDate = CAST(N'2026-04-06 00:00:00' AS DATETIME);
    SET @Op2 = @@ROWCOUNT;

    /* -- 3. UPDATE Update_EndEffDate -- */
    DECLARE @Stg3 TABLE (
        [HTSNum] varchar(20),
        [Chapter99] varchar(20),
        [CountryofOrigin] varchar(10),
        [TariffType] varchar(20),
        [New_EndEffDate] datetime
    );

    UPDATE t
       SET t.[EndEffDate] = k.[New_EndEffDate]
    FROM dbo.tmdHTSAdditional t
    JOIN @Stg3 k
      ON  ISNULL(t.[HTSNum],'') = ISNULL(k.[HTSNum],'')
      AND t.[Chapter99] = k.[Chapter99]
      AND ISNULL(t.[CountryofOrigin],'') = ISNULL(k.[CountryofOrigin],'')
      AND t.[TariffType] = k.[TariffType]
    WHERE t.EndEffDate = CAST(N'9999-12-31 23:59:59' AS DATETIME);
    SET @Op3 = @@ROWCOUNT;

    /* -- 4. INSERT Inserts_tmdhtsadditional -- */
    DECLARE @Stg4 TABLE (
        [HTSNum] varchar(20),
        [Chapter99] varchar(20),
        [CountryofOrigin] varchar(10),
        [StartEffDate] datetime,
        [EndEffDate] datetime,
        [TariffType] varchar(20),
        [TariffGroup] varchar(20),
        [RequiredStatusCode] varchar(1),
        [ValidationLevel] varchar(1),
        [ExportDate] datetime
    );

    SELECT s.[HTSNum], s.[Chapter99], s.[CountryofOrigin], s.[StartEffDate], s.[EndEffDate], s.[TariffType], s.[TariffGroup], s.[RequiredStatusCode], s.[ValidationLevel], s.[ExportDate]
    FROM @Stg4 s
    WHERE NOT EXISTS (
        SELECT 1 FROM dbo.tmdHTSAdditional t WITH (NOLOCK)
        WHERE ISNULL(t.[HTSNum],'') = ISNULL(s.[HTSNum],'')
          AND t.[Chapter99] = s.[Chapter99]
          AND t.[TariffType] = s.[TariffType]
          AND ISNULL(t.[CountryofOrigin],'') = ISNULL(s.[CountryofOrigin],'')
          AND t.[StartEffDate] = s.[StartEffDate]
    );
    SET @Op4 = @@ROWCOUNT;

    SELECT [Phase]='PASS 1 (applied, uncommitted)', [DELETE_1]=@Op1, [UPDATE_2]=@Op2, [UPDATE_3]=@Op3, [INSERT_4]=@Op4;

    /* ===== PASS 2 (idempotency re-run; expect all 0) ===== */
    /* -- 1. DELETE Deletes -- */
    DELETE FROM dbo.tmdHTSAdditional
    WHERE Chapter99 = '99038212' AND TariffType = '232' AND ( (ISNULL(HTSNum,'') = '' AND ISNULL(CountryofOrigin,'') IN ('BY','CU','KP','RU')) OR (ISNULL(HTSNum,'') <> '' AND ISNULL(CountryofOrigin,'') = '') );
    SET @Op1b = @@ROWCOUNT;

    /* -- 2. UPDATE Update_StartEffDate -- */
    UPDATE t
       SET t.[StartEffDate] = k.[New_StartEffDate]
    FROM dbo.tmdHTSAdditional t
    JOIN @Stg2 k
      ON  ISNULL(t.[HTSNum],'') = ISNULL(k.[HTSNum],'')
      AND t.[Chapter99] = k.[Chapter99]
      AND t.[TariffType] = k.[TariffType]
    WHERE t.StartEffDate = CAST(N'2026-04-06 00:00:00' AS DATETIME);
    SET @Op2b = @@ROWCOUNT;

    /* -- 3. UPDATE Update_EndEffDate -- */
    UPDATE t
       SET t.[EndEffDate] = k.[New_EndEffDate]
    FROM dbo.tmdHTSAdditional t
    JOIN @Stg3 k
      ON  ISNULL(t.[HTSNum],'') = ISNULL(k.[HTSNum],'')
      AND t.[Chapter99] = k.[Chapter99]
      AND ISNULL(t.[CountryofOrigin],'') = ISNULL(k.[CountryofOrigin],'')
      AND t.[TariffType] = k.[TariffType]
    WHERE t.EndEffDate = CAST(N'9999-12-31 23:59:59' AS DATETIME);
    SET @Op3b = @@ROWCOUNT;

    /* -- 4. INSERT Inserts_tmdhtsadditional -- */
    SELECT s.[HTSNum], s.[Chapter99], s.[CountryofOrigin], s.[StartEffDate], s.[EndEffDate], s.[TariffType], s.[TariffGroup], s.[RequiredStatusCode], s.[ValidationLevel], s.[ExportDate]
    FROM @Stg4 s
    WHERE NOT EXISTS (
        SELECT 1 FROM dbo.tmdHTSAdditional t WITH (NOLOCK)
        WHERE ISNULL(t.[HTSNum],'') = ISNULL(s.[HTSNum],'')
          AND t.[Chapter99] = s.[Chapter99]
          AND t.[TariffType] = s.[TariffType]
          AND ISNULL(t.[CountryofOrigin],'') = ISNULL(s.[CountryofOrigin],'')
          AND t.[StartEffDate] = s.[StartEffDate]
    );
    SET @Op4b = @@ROWCOUNT;

    SELECT [Phase]='PASS 2 (idempotency)', [DELETE_1]=@Op1b, [UPDATE_2]=@Op2b, [UPDATE_3]=@Op3b, [INSERT_4]=@Op4b,
           [Idempotent]=CASE WHEN @Op1b=0 AND @Op2b=0 AND @Op3b=0 AND @Op4b=0 THEN 'PASS' ELSE 'FAIL' END;

    /* ===== AC VERIFICATION (uncommitted state) ===== */
/* ---- Backup exists (AC-1/AC-2) ---- */
DECLARE @v_BackupRows INT = NULL;
IF OBJECT_ID(N'[bck].[bck_tmdHTSAdditional_232_Metals_CSMS68855869_20260610_5462916]','U') IS NOT NULL
BEGIN
    DECLARE @v_bsql nvarchar(max) = N'SELECT @c = COUNT(*) FROM [bck].[bck_tmdHTSAdditional_232_Metals_CSMS68855869_20260610_5462916] WITH (NOLOCK)';
    EXEC sys.sp_executesql @v_bsql, N'@c INT OUTPUT', @c = @v_BackupRows OUTPUT;
END
SELECT [AC] = 'Backup', [BackupTable] = N'[bck].[bck_tmdHTSAdditional_232_Metals_CSMS68855869_20260610_5462916]',
       [Exists] = CASE WHEN OBJECT_ID(N'[bck].[bck_tmdHTSAdditional_232_Metals_CSMS68855869_20260610_5462916]','U') IS NOT NULL THEN 1 ELSE 0 END, [RowCount] = @v_BackupRows;

/* ---- Op 1 DELETE: no rows match the delete pattern remain (EXPECTED 0) ---- */
SELECT [AC] = 'Op1 delete-remaining', [Remaining] = COUNT(*)
FROM dbo.tmdHTSAdditional WITH (NOLOCK) WHERE Chapter99 = '99038212' AND TariffType = '232' AND ( (ISNULL(HTSNum,'') = '' AND ISNULL(CountryofOrigin,'') IN ('BY','CU','KP','RU')) OR (ISNULL(HTSNum,'') <> '' AND ISNULL(CountryofOrigin,'') = '') );

/* ---- Op 2 UPDATE: target rows carry the new StartEffDate ---- */
DECLARE @v_upd2 TABLE (
    [HTSNum] varchar(20),
    [Chapter99] varchar(20),
    [TariffType] varchar(20),
    [New_StartEffDate] datetime
);
SELECT [AC]='Op2 update', [expected]=(SELECT COUNT(*) FROM @v_upd2),
       [matched]=COUNT(*)
FROM dbo.tmdHTSAdditional t WITH (NOLOCK)
JOIN @v_upd2 k ON ISNULL(t.[HTSNum],'') = ISNULL(k.[HTSNum],'') AND t.[Chapter99] = k.[Chapter99] AND t.[TariffType] = k.[TariffType] AND t.[StartEffDate] = k.[New_StartEffDate];

/* ---- Op 3 UPDATE: target rows carry the new EndEffDate ---- */
DECLARE @v_upd3 TABLE (
    [HTSNum] varchar(20),
    [Chapter99] varchar(20),
    [CountryofOrigin] varchar(10),
    [TariffType] varchar(20),
    [New_EndEffDate] datetime
);
SELECT [AC]='Op3 update', [expected]=(SELECT COUNT(*) FROM @v_upd3),
       [matched]=COUNT(*)
FROM dbo.tmdHTSAdditional t WITH (NOLOCK)
JOIN @v_upd3 k ON ISNULL(t.[HTSNum],'') = ISNULL(k.[HTSNum],'') AND t.[Chapter99] = k.[Chapter99] AND ISNULL(t.[CountryofOrigin],'') = ISNULL(k.[CountryofOrigin],'') AND t.[TariffType] = k.[TariffType] AND t.[EndEffDate] = k.[New_EndEffDate];

/* ---- Op 4 INSERT: payload-scoped count per Chapter99 ---- */
DECLARE @v_ins4 TABLE (
    [HTSNum] varchar(20),
    [Chapter99] varchar(20),
    [TariffType] varchar(20),
    [CountryofOrigin] varchar(10),
    [StartEffDate] datetime
);
DECLARE @v_exp4 TABLE ([grp] nvarchar(60), [expected] int);
SELECT [AC]='Op4 per Chapter99', e.[grp], e.[expected],
       [present] = (SELECT COUNT(*) FROM dbo.tmdHTSAdditional t WITH (NOLOCK) WHERE EXISTS (SELECT 1 FROM @v_ins4 s WHERE ISNULL(t.[HTSNum],'') = ISNULL(s.[HTSNum],'') AND t.[Chapter99] = s.[Chapter99] AND t.[TariffType] = s.[TariffType] AND ISNULL(t.[CountryofOrigin],'') = ISNULL(s.[CountryofOrigin],'') AND t.[StartEffDate] = s.[StartEffDate]) AND t.[Chapter99] = e.[grp]),
       [Status] = CASE WHEN e.[expected] = (SELECT COUNT(*) FROM dbo.tmdHTSAdditional t WITH (NOLOCK) WHERE EXISTS (SELECT 1 FROM @v_ins4 s WHERE ISNULL(t.[HTSNum],'') = ISNULL(s.[HTSNum],'') AND t.[Chapter99] = s.[Chapter99] AND t.[TariffType] = s.[TariffType] AND ISNULL(t.[CountryofOrigin],'') = ISNULL(s.[CountryofOrigin],'') AND t.[StartEffDate] = s.[StartEffDate]) AND t.[Chapter99] = e.[grp]) THEN 'PASS' ELSE 'FAIL' END
FROM @v_exp4 e ORDER BY e.[grp];

/* ---- Op 4 INSERT: no duplicates on key (EXPECTED 0) ---- */
SELECT [AC]='Op4 no-dup', ISNULL(t.[HTSNum],''), t.[Chapter99], t.[TariffType], ISNULL(t.[CountryofOrigin],''), t.[StartEffDate], [n]=COUNT(*)
FROM dbo.tmdHTSAdditional t WITH (NOLOCK)
WHERE EXISTS (SELECT 1 FROM @v_ins4 s WHERE ISNULL(t.[HTSNum],'') = ISNULL(s.[HTSNum],'') AND t.[Chapter99] = s.[Chapter99] AND t.[TariffType] = s.[TariffType] AND ISNULL(t.[CountryofOrigin],'') = ISNULL(s.[CountryofOrigin],'') AND t.[StartEffDate] = s.[StartEffDate])
GROUP BY ISNULL(t.[HTSNum],''), t.[Chapter99], t.[TariffType], ISNULL(t.[CountryofOrigin],''), t.[StartEffDate] HAVING COUNT(*) > 1;

/* ---- Sign-off roll-up (every column should read PASS) ---- */
SELECT
     [Backup exists] = CASE WHEN OBJECT_ID(N'[bck].[bck_tmdHTSAdditional_232_Metals_CSMS68855869_20260610_5462916]','U') IS NOT NULL THEN 'PASS' ELSE 'FAIL' END
    ,[Op1 deleted] = CASE WHEN NOT EXISTS (SELECT 1 FROM dbo.tmdHTSAdditional WITH (NOLOCK) WHERE Chapter99 = '99038212' AND TariffType = '232' AND ( (ISNULL(HTSNum,'') = '' AND ISNULL(CountryofOrigin,'') IN ('BY','CU','KP','RU')) OR (ISNULL(HTSNum,'') <> '' AND ISNULL(CountryofOrigin,'') = '') )) THEN 'PASS' ELSE 'FAIL' END
    ,[Op2 update] = CASE WHEN (SELECT COUNT(*) FROM dbo.tmdHTSAdditional t WITH (NOLOCK) JOIN @v_upd2 k ON ISNULL(t.[HTSNum],'') = ISNULL(k.[HTSNum],'') AND t.[Chapter99] = k.[Chapter99] AND t.[TariffType] = k.[TariffType] AND t.[StartEffDate] = k.[New_StartEffDate]) = (SELECT COUNT(*) FROM @v_upd2) THEN 'PASS' ELSE 'FAIL' END
    ,[Op3 update] = CASE WHEN (SELECT COUNT(*) FROM dbo.tmdHTSAdditional t WITH (NOLOCK) JOIN @v_upd3 k ON ISNULL(t.[HTSNum],'') = ISNULL(k.[HTSNum],'') AND t.[Chapter99] = k.[Chapter99] AND ISNULL(t.[CountryofOrigin],'') = ISNULL(k.[CountryofOrigin],'') AND t.[TariffType] = k.[TariffType] AND t.[EndEffDate] = k.[New_EndEffDate]) = (SELECT COUNT(*) FROM @v_upd3) THEN 'PASS' ELSE 'FAIL' END
    ,[Op4 per Chapter99] = CASE WHEN NOT EXISTS (SELECT 1 FROM @v_exp4 e WHERE e.[expected] <> (SELECT COUNT(*) FROM dbo.tmdHTSAdditional t WITH (NOLOCK) WHERE EXISTS (SELECT 1 FROM @v_ins4 s WHERE ISNULL(t.[HTSNum],'') = ISNULL(s.[HTSNum],'') AND t.[Chapter99] = s.[Chapter99] AND t.[TariffType] = s.[TariffType] AND ISNULL(t.[CountryofOrigin],'') = ISNULL(s.[CountryofOrigin],'') AND t.[StartEffDate] = s.[StartEffDate]) AND t.[Chapter99] = e.[grp])) THEN 'PASS' ELSE 'FAIL' END
    ,[Op4 no-dup] = CASE WHEN NOT EXISTS (SELECT 1 FROM dbo.tmdHTSAdditional t WITH (NOLOCK) WHERE EXISTS (SELECT 1 FROM @v_ins4 s WHERE ISNULL(t.[HTSNum],'') = ISNULL(s.[HTSNum],'') AND t.[Chapter99] = s.[Chapter99] AND t.[TariffType] = s.[TariffType] AND ISNULL(t.[CountryofOrigin],'') = ISNULL(s.[CountryofOrigin],'') AND t.[StartEffDate] = s.[StartEffDate]) GROUP BY ISNULL(t.[HTSNum],''), t.[Chapter99], t.[TariffType], ISNULL(t.[CountryofOrigin],''), t.[StartEffDate] HAVING COUNT(*)>1) THEN 'PASS' ELSE 'FAIL' END;

    IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
    PRINT '*** ROLLED BACK -- nothing persisted. ***';
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
    SELECT [Phase]='ERROR (rolled back)', [ErrLine]=ERROR_LINE(), [ErrMsg]=ERROR_MESSAGE();
END CATCH;
